using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.DependencyInjection;
using System.IO;

namespace FileUploadEndpoint
{
    public class Startup
    {
        public void ConfigureServices(IServiceCollection services)
        {
            services.AddAntiforgery(options =>
            {
                options.Cookie.Name = "my_antiforgery";
                options.RequireSsl = false;
            });
            services.AddControllersWithViews();
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            if (env.IsDevelopment())
            {
                app.UseDeveloperExceptionPage();
            }
            else
            {
                app.UseExceptionHandler("/Home/Error");
            }

            app.UseHttpsRedirection();

            // Support common file types
            app.UseStaticFiles(new StaticFileOptions()
            {
                FileProvider = new PhysicalFileSystem(env.ContentRootPath + "/uploads"),
                RequestPath = "/uploads"
            });
        }
    }

    public class UploadController : Controller
    {
        [HttpPost]
        public IActionResult Index(IFormFile file)
        {
            if (file == null || file.Length < 1)
            {
                return BadRequest();
            }
            var allowedTypes = new[] { "image/*", "application/pdf", "application/msword", "application/vnd.openxmlformats-officedocument.wordprocessingml.document" };
            string fileExtension;
            string fileName;
            if (file.ContentType.Contains("image"))
            {
                fileExtension = ".jpg";
                fileName = $"avatar_{DateTime.Now.ToString("yyyyMMddHHmmss")}{fileExtension}";
            }
            else
            {
                fileExtension = "." + file.FileName.Split('.').Last();
                fileName = $"{Guid.NewGuid()}{fileExtension}";
            }

            string filePath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot/uploads", fileName);
            using (var stream = new FileStream(filePath, FileMode.CreateNew))
            {
                file.CopyTo(stream);
            }
            return Ok($"Upload successful. File path: {filePath}");
        }
    }
